/**
 * Checks whether a point is isolated
 *
 * @param points - array of data
 * @param index - current index of the point
 * @param isDefined - accessor to check if a given point is defined
 * @returns boolean
 */
export declare function isIsolatedPoint<Datum>(points: Datum[], index: number, isDefined: (point: Datum) => boolean): boolean;
